import{_ as s,o as a,c as e,ae as i}from"./chunks/framework.C1F7hH3b.js";const c=JSON.parse('{"title":"如何检查 macOS 系统内安装的 Electron 应用","description":"","frontmatter":{"title":"如何检查 macOS 系统内安装的 Electron 应用"},"headers":[],"relativePath":"blog/如何检查macOS系统内安装的electron应用.md","filePath":"blog/如何检查macOS系统内安装的electron应用.md","lastUpdated":1780898795000}'),o={name:"blog/如何检查macOS系统内安装的electron应用.md"};function r(n,t,d,h,l,p){return a(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="如何检查-macos-系统内安装的-electron-应用" tabindex="-1">如何检查 macOS 系统内安装的 Electron 应用 <a class="header-anchor" href="#如何检查-macos-系统内安装的-electron-应用" aria-label="Permalink to &quot;如何检查 macOS 系统内安装的 Electron 应用&quot;">​</a></h1><p>最近清理电脑时，我突然好奇：我的 macOS 里到底装了多少个 Electron 应用？比如 VSCode、Slack、Notion 这些看起来&quot;不一样&quot;的软件，背后其实都是 Electron 写的。</p><p>这篇文章就教大家如何找出系统中所有由 Electron 构建的应用程序，顺便也能查出所有&quot;内置了浏览器&quot;的应用（CEF、Chrome、QtWebEngine 等）。</p><h2 id="什么是-electron-内置浏览器的应用" tabindex="-1">什么是 Electron / 内置浏览器的应用？ <a class="header-anchor" href="#什么是-electron-内置浏览器的应用" aria-label="Permalink to &quot;什么是 Electron / 内置浏览器的应用？&quot;">​</a></h2><p>简单来说，<strong>Electron</strong> 是一个用 Web 技术开发桌面应用的框架。它把 Chromium 和 Node.js 打包在一起，外面看是个原生 App，骨子里其实是个浏览器。</p><p>类似的&quot;内置浏览器&quot;技术还有：</p><table tabindex="0"><thead><tr><th>技术</th><th>引擎</th><th>典型应用</th></tr></thead><tbody><tr><td>Electron</td><td>Chromium</td><td>VSCode、Slack、Notion、Discord</td></tr><tr><td>CEF（Chromium Embedded Framework）</td><td>Chromium</td><td>剪映专业版、Spotify、Steam</td></tr><tr><td>Qt WebEngine</td><td>Chromium</td><td>WPS、OBS 等跨平台应用</td></tr><tr><td>WebKit</td><td>WebKit</td><td>各种带&quot;在线预览&quot;的小工具</td></tr></tbody></table><blockquote><p><strong>共同点</strong>：都把一个完整的浏览器引擎塞进了自己的 <code>.app</code> 包里。</p></blockquote><h2 id="核心检测方法-find-name" tabindex="-1">核心检测方法：<code>find -name</code> <a class="header-anchor" href="#核心检测方法-find-name" aria-label="Permalink to &quot;核心检测方法：\`find -name\`&quot;">​</a></h2><p>这些应用有个共同特征——它们的 <code>.app</code> 包里都会带一个<strong>特征 framework</strong>。所以检测的核心思路就是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;特征 framework 名&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre></div><blockquote><p>macOS 绝大多数应用都装在 <code>/Applications</code> 下，找到 framework 就能反推出应用。</p></blockquote><p>下面是常见的 framework 名和对应的引擎：</p><table tabindex="0"><thead><tr><th>Framework 名</th><th>引擎</th></tr></thead><tbody><tr><td><code>Electron Framework.framework</code></td><td>Electron</td></tr><tr><td><code>Chromium Embedded Framework.framework</code></td><td>CEF</td></tr><tr><td><code>Google Chrome Framework.framework</code></td><td>Chrome</td></tr><tr><td><code>Chromium Framework.framework</code></td><td>Chromium</td></tr><tr><td><code>QtWebEngineCore.framework</code> / <code>QtWebEngine.framework</code></td><td>Qt WebEngine</td></tr><tr><td><code>WebKit.framework</code> / <code>WebKit2.framework</code></td><td>WebKit</td></tr><tr><td><code>MozillaFirefox.framework</code> / <code>Gecko.framework</code></td><td>Firefox</td></tr><tr><td><code>nwjs.framework</code></td><td>NW.js</td></tr></tbody></table><h3 id="几个常用示例" tabindex="-1">几个常用示例 <a class="header-anchor" href="#几个常用示例" aria-label="Permalink to &quot;几个常用示例&quot;">​</a></h3><p><strong>找出所有 Electron 应用：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Electron Framework.framework&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre></div><p><strong>找出所有 Chromium 应用：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Chromium Framework.framework&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre></div><h2 id="深度排查-用-otool-看单个应用" tabindex="-1">深度排查：用 <code>otool</code> 看单个应用 <a class="header-anchor" href="#深度排查-用-otool-看单个应用" aria-label="Permalink to &quot;深度排查：用 \`otool\` 看单个应用&quot;">​</a></h2><p><code>otool</code> 是 macOS 自带的工具，可以看应用到底链接了哪些 framework。当你不确定某个应用是不是&quot;套壳浏览器&quot;时，用它最准确。</p><h2 id="使用otool实现的完整可运行的扫描脚本" tabindex="-1">使用otool实现的完整可运行的扫描脚本 <a class="header-anchor" href="#使用otool实现的完整可运行的扫描脚本" aria-label="Permalink to &quot;使用otool实现的完整可运行的扫描脚本&quot;">​</a></h2><p>如果你懒得一行一行敲命令，可以直接用下面这个<strong>完整脚本</strong>。它会自动扫描常见位置、检测 18 种浏览器引擎，并输出应用名、版本、占用空间、bundle id 等详细信息。</p><p>脚本地址： <a href="https://codemyhappy.github.io/static/macshell/detect_browser_apps.sh" target="_blank" rel="noreferrer">https://codemyhappy.github.io/static/macshell/detect_browser_apps.sh</a></p><h3 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect_browser_apps.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./detect_browser_apps.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 标准扫描</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./detect_browser_apps.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --full</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 深度扫描</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./detect_browser_apps.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --deep</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 全用户主目录扫描</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./detect_browser_apps.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out.json</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 导出 JSON</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./detect_browser_apps.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --csv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out.csv</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 导出 CSV</span></span></code></pre></div><h3 id="小贴士" tabindex="-1">小贴士 <a class="header-anchor" href="#小贴士" aria-label="Permalink to &quot;小贴士&quot;">​</a></h3><ul><li>在 <strong><code>--deep</code></strong> 模式下会扫 <code>users/</code> 下的所有用户目录，可能需要 1-3 分钟</li><li>脚本不会修改系统任何文件，<strong>完全只读</strong>，可以放心运行</li></ul><p>到这里，本文就结束了。希望对你有帮助！</p>`,29)])])}const g=s(o,[["render",r]]);export{c as __pageData,g as default};
